external_knowledge:
- 'most devoted shoppers' refers to the users who have accessed a product the most times;
- 'frequent visits' refers to the maximum access count;
- 'overall purchases' and 'total spending' refer to the total sold and total revenue, respectively;
- 'total interactions' and 'diverse product interests' refer to the total accesses and unique products accessed, respectively.

sql:
SELECT SUM(s.revenue) AS total_revenue
FROM sales s
WHERE strftime('%Y-%m', s.sale_date) = '2023-05';
